const rawInput = $input.first().json.chatInput || "";
const rawUrls = rawInput.split(/[\s,]+/).filter(Boolean);

let validUrls = [];
let skipped = [];
const urlRegex = /^(https?:\/\/)?([\da-z\.-]+)\.([a-z\.]{2,6})([\/\w \.-]*)*\/?$/i;

for (let url of rawUrls) {
  if (!urlRegex.test(url)) {
    skipped.push(url);
    continue;
  }
  let clean = url.toLowerCase();
  if (!clean.startsWith('http://') && !clean.startsWith('https://')) {
    clean = 'https://' + clean;
  }
  if (!validUrls.includes(clean)) {
    validUrls.push(clean);
  }
}

let warning = "";
if (validUrls.length > 10) {
  warning = "⚠️ Only the first 10 URLs will be processed. Remaining URLs have been skipped.";
  validUrls = validUrls.slice(0, 10);
}

return [{
  json: {
    valid_urls: validUrls,
    skipped_input: skipped,
    warning: warning,
    total_valid: validUrls.length
  }
}];

// 1. Get all items from the current node (Reachability Check)
const items = $input.all();

// 2. Map through them to output only the two fields you want
return items.map((item, index) => {

  // REACHBACK: Get the URL from the Split node using the index
  const splitNodeData = $('Split Valid URLs').all();
  const url = splitNodeData[index]?.json?.valid_urls || "URL Not Found";

  // DATA EXTRACTION: Pull status from the Reachability node
  const statusCode = item.json.statusCode || item.json.metadata?.statusCode;

  return {
    json: {
      valid_urls: url,
      status: statusCode
    }
  };
});

const items = $input.all();
let results = [];

for (const entry of items) {
  const item = entry.json;
  const lh = item.lighthouseResult;

  // 1. RESILIENCE: Catch missing Lighthouse data
  if (!lh) {
    results.push({
      "Address": item.id || "Unknown URL",
      "PSI Request Status": "Error: No Lighthouse Data",
      "Performance Score": 0
    });
    continue;
  }

  const audits = lh.audits || {};
  const categories = lh.categories || {};

  // HELPER: Resource Summary
  const getRes = (type) => {
    const summary = audits['resource-summary'];
    const resItems = (summary && summary.details && summary.details.items) ? summary.details.items : [];
    const res = resItems.find(i => i.resourceType === type);
    return { size: res ? res.transferSize : 0, count: res ? res.requestCount : 0 };
  };

  // HELPER: Savings (Updated for v13 Insight Schema)
  const getSav = (id) => {
    const audit = audits[id];
    if (!audit) return { bytes: 0, ms: 0 };

    const details = audit.details || {};
    const metricSavings = audit.metricSavings || {};
    const debugData = details.debugData || {};

    // Logic to handle varying locations of savings data in modern audits
    const bytes = details.overallSavingsBytes || details.wastedBytes || debugData.wastedBytes || 0;
    const ms = details.overallSavingsMs || details.wastedMs || audit.numericValue || metricSavings.FCP || metricSavings.LCP || 0;

    return { bytes, ms };
  };

  // HELPER: Category Mapper
  const getCat = (score) => {
    if (score === null || score === undefined) return "N/A";
    if (score >= 0.9) return "Good";
    if (score >= 0.5) return "Needs Improvement";
    return "Poor";
  };

  // Pre-fetch nested insight objects to avoid long logical chains
  const docLatency = audits['document-latency-insight'];
  const lcpDiscovery = audits['lcp-discovery-insight'];
  const netTree = audits['network-dependency-tree-insight'];
  const thirdParties = audits['third-parties-insight'];

  results.push({
    "Address": lh.finalUrl || item.id,
    "PSI Request Status": "Success",
    "Performance Score": Math.round((categories.performance ? categories.performance.score : 0) * 100),

    // LAB METRICS
    "First Contentful Paint Time (ms)": audits['first-contentful-paint'] ? audits['first-contentful-paint'].numericValue : 0,
    "First Contentful Paint Score": Math.round((audits['first-contentful-paint'] ? audits['first-contentful-paint'].score : 0) * 100),
    "Speed Index Time (ms)": audits['speed-index'] ? audits['speed-index'].numericValue : 0,
    "Speed Index Score": Math.round((audits['speed-index'] ? audits['speed-index'].score : 0) * 100),
    "Largest Contentful Paint Time (ms)": audits['largest-contentful-paint'] ? audits['largest-contentful-paint'].numericValue : 0,
    "Largest Contentful Paint Score": Math.round((audits['largest-contentful-paint'] ? audits['largest-contentful-paint'].score : 0) * 100),
    "Time to Interactive (ms)": audits['interactive'] ? audits['interactive'].numericValue : 0,
    "Time to Interactive Score": Math.round((audits['interactive'] ? audits['interactive'].score : 0) * 100),
    "Max Potential First Input Delay (ms)": audits['max-potential-fid'] ? audits['max-potential-fid'].numericValue : 0,
    "Max Potential First Input Delay Score": Math.round((audits['max-potential-fid'] ? audits['max-potential-fid'].score : 0) * 100),
    "Total Blocking Time (ms)": audits['total-blocking-time'] ? audits['total-blocking-time'].numericValue : 0,
    "Total Blocking Time Score": Math.round((audits['total-blocking-time'] ? audits['total-blocking-time'].score : 0) * 100),
    "Cumulative Layout Shift": audits['cumulative-layout-shift'] ? audits['cumulative-layout-shift'].numericValue : 0,
    "Cumulative Layout Shift Score": Math.round((audits['cumulative-layout-shift'] ? audits['cumulative-layout-shift'].score : 0) * 100),

    // AGGREGATED SAVINGS
    "Total Size Savings (Bytes)": (getSav('unused-javascript').bytes + getSav('unused-css-rules').bytes),
    "Total Time Savings (ms)": getSav('render-blocking-insight').ms,

    // PAGE COMPOSITION
    "Total Requests": getRes('total').count,
    "Total Page Size (Bytes)": getRes('total').size,
    "HTML Size (Bytes)": getRes('document').size,
    "HTML Count": getRes('document').count,
    "Image Size (Bytes)": getRes('image').size,
    "Image Count": getRes('image').count,
    "CSS Size (Bytes)": getRes('stylesheet').size,
    "CSS Count": getRes('stylesheet').count,
    "JavaScript Size (Bytes)": getRes('script').size,
    "JavaScript Count": getRes('script').count,
    "Font Size (Bytes)": getRes('font').size,
    "Font Count": getRes('font').count,
    "Third Party Size (Bytes)": getRes('third-party').size,
    "Third Party Count": getRes('third-party').count,

    // GRANULAR SAVINGS
    "Minify CSS Savings (ms)": getSav('unminified-css').ms,
    "Minify CSS Savings (Bytes)": getSav('unminified-css').bytes,
    "Minify JavaScript Savings (ms)": getSav('unminified-javascript').ms,
    "Minify JavaScript Savings (Bytes)": getSav('unminified-javascript').bytes,
    "Reduce Unused CSS Savings (ms)": getSav('unused-css-rules').ms,
    "Reduce Unused CSS Savings (Bytes)": getSav('unused-css-rules').bytes,
    "Reduce Unused JavaScript Savings (ms)": getSav('unused-javascript').ms,
    "Reduce Unused JavaScript Savings (Bytes)": getSav('unused-javascript').bytes,

    // ADVANCED DIAGNOSTICS & INSIGHT MAPPINGS
    "JavaScript Execution Time (ms)": audits['bootup-time'] ? audits['bootup-time'].numericValue : 0,
    "JavaScript Execution Time Category": getCat(audits['bootup-time'] ? audits['bootup-time'].score : 0),
    "Minimize Main-Thread Work (ms)": audits['mainthread-work-breakdown'] ? audits['mainthread-work-breakdown'].numericValue : 0,
    "Minimize Main-Thread Work Category": getCat(audits['mainthread-work-breakdown'] ? audits['mainthread-work-breakdown'].score : 0),
    "Network Payload Size (Bytes)": audits['total-byte-weight'] ? audits['total-byte-weight'].numericValue : 0,
    "Accessibility Score": Math.round((categories.accessibility ? categories.accessibility.score : 0) * 100),
    "Server Responds Quickly": audits['server-response-time'] ? audits['server-response-time'].displayValue : "N/A",

    // Corrected logic for nested v13 Insight items
    "Applies Text Compression": (docLatency && docLatency.details && docLatency.details.items && docLatency.details.items.usesCompression && docLatency.details.items.usesCompression.value) ? "Yes" : "No",
    "LCP Request Discovery": (lcpDiscovery && lcpDiscovery.details && lcpDiscovery.details.items && lcpDiscovery.details.items.requestDiscoverable && lcpDiscovery.details.items.requestDiscoverable.value) ? "Optimized" : "Action Required",
    "LCP Breakdown": (audits['lcp-breakdown-insight'] && audits['lcp-breakdown-insight'].details && audits['lcp-breakdown-insight'].details.items ? audits['lcp-breakdown-insight'].details.items.length : 0) + " segments",

    "Render Blocking Requests Savings (ms)": getSav('render-blocking-insight').ms,
    "Preconnect Candidates Savings (ms)": getSav('uses-rel-preconnect').ms,
    "Maximum Critical Path Latency (ms)": (netTree && netTree.details && netTree.details.items && netTree.details.items.value && netTree.details.items.value.longestChain) ? netTree.details.items.value.longestChain.duration : 0,
    "Use Efficient Cache Lifetimes Savings (Bytes)": getSav('cache-insight').bytes,
    "Layout Shift Culprits": (audits['cls-culprits-insight'] && audits['cls-culprits-insight'].details && audits['cls-culprits-insight'].details.items) ? audits['cls-culprits-insight'].details.items.length : 0,
    "DOM Size": audits['dom-size-insight'] ? audits['dom-size-insight'].numericValue : 0,
    "Improve Image Delivery Savings (Bytes)": getSav('image-delivery-insight').bytes,
    "Forced Reflow Savings (ms)": getSav('forced-reflow-insight').ms,
    "Legacy JavaScript Savings (Bytes)": getSav('legacy-javascript-insight').bytes,
    "Duplicated JavaScript (Bytes)": getSav('duplicated-javascript-insight').bytes,
    "Font Display Savings (ms)": getSav('font-display-insight').ms,
    "3rd Parties": (thirdParties && thirdParties.details && thirdParties.details.items ? thirdParties.details.items.length : 0) + " resources found"
  });
}

return results.map(r => ({ json: r }));
